(window.webpackJsonp=window.webpackJsonp||[]).push([[736],{706:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code>\\n<span class=\\"hljs-keyword\\">var</span> ProductOfNumbers = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.arr=[]\\n  <span class=\\"hljs-keyword\\">this</span>.prd=[]\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} num\\n * @return {void}\\n */</span>\\nProductOfNumbers.prototype.add = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">num</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.arr.push(num)\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-keyword\\">this</span>.prd.length;i++){\\n    <span class=\\"hljs-keyword\\">this</span>.prd[i]*=num\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.prd.push(num)\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} k\\n * @return {number}\\n */</span>\\nProductOfNumbers.prototype.getProduct = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.prd[<span class=\\"hljs-keyword\\">this</span>.prd.length-k]\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your ProductOfNumbers object will be instantiated and called as such:\\n * var obj = new ProductOfNumbers()\\n * obj.add(num)\\n * var param_2 = obj.getProduct(k)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"product-of-the-last-k-numbers","hasThinking":false,"content":"<p>\u8bf7\u4f60\u5b9e\u73b0\u4e00\u4e2a\u300c\u6570\u5b57\u4e58\u79ef\u7c7b\u300d<code>ProductOfNumbers</code>\uff0c\u8981\u6c42\u652f\u6301\u4e0b\u8ff0\u4e24\u79cd\u65b9\u6cd5\uff1a</p>\\n\\n<p>1.<code>&nbsp;add(int num)</code></p>\\n\\n<ul>\\n\\t<li>\u5c06\u6570\u5b57&nbsp;<code>num</code>&nbsp;\u6dfb\u52a0\u5230\u5f53\u524d\u6570\u5b57\u5217\u8868\u7684\u6700\u540e\u9762\u3002</li>\\n</ul>\\n\\n<p>2.<code> getProduct(int k)</code></p>\\n\\n<ul>\\n\\t<li>\u8fd4\u56de\u5f53\u524d\u6570\u5b57\u5217\u8868\u4e2d\uff0c\u6700\u540e&nbsp;<code>k</code>&nbsp;\u4e2a\u6570\u5b57\u7684\u4e58\u79ef\u3002</li>\\n\\t<li>\u4f60\u53ef\u4ee5\u5047\u8bbe\u5f53\u524d\u5217\u8868\u4e2d\u59cb\u7ec8 <strong>\u81f3\u5c11</strong> \u5305\u542b <code>k</code> \u4e2a\u6570\u5b57\u3002</li>\\n</ul>\\n\\n<p>\u9898\u76ee\u6570\u636e\u4fdd\u8bc1\uff1a\u4efb\u4f55\u65f6\u5019\uff0c\u4efb\u4e00\u8fde\u7eed\u6570\u5b57\u5e8f\u5217\u7684\u4e58\u79ef\u90fd\u5728 32-bit \u6574\u6570\u8303\u56f4\u5185\uff0c\u4e0d\u4f1a\u6ea2\u51fa\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\n[&quot;ProductOfNumbers&quot;,&quot;add&quot;,&quot;add&quot;,&quot;add&quot;,&quot;add&quot;,&quot;add&quot;,&quot;getProduct&quot;,&quot;getProduct&quot;,&quot;getProduct&quot;,&quot;add&quot;,&quot;getProduct&quot;]\\n[[],[3],[0],[2],[5],[4],[2],[3],[4],[8],[2]]\\n\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,null,null,null,null,null,20,40,0,null,32]\\n\\n<strong>\u89e3\u91ca\uff1a</strong>\\nProductOfNumbers productOfNumbers = new ProductOfNumbers();\\nproductOfNumbers.add(3);        // [3]\\nproductOfNumbers.add(0);        // [3,0]\\nproductOfNumbers.add(2);        // [3,0,2]\\nproductOfNumbers.add(5);        // [3,0,2,5]\\nproductOfNumbers.add(4);        // [3,0,2,5,4]\\nproductOfNumbers.getProduct(2); // \u8fd4\u56de 20 \u3002\u6700\u540e 2 \u4e2a\u6570\u5b57\u7684\u4e58\u79ef\u662f 5 * 4 = 20\\nproductOfNumbers.getProduct(3); // \u8fd4\u56de 40 \u3002\u6700\u540e 3 \u4e2a\u6570\u5b57\u7684\u4e58\u79ef\u662f 2 * 5 * 4 = 40\\nproductOfNumbers.getProduct(4); // \u8fd4\u56de  0 \u3002\u6700\u540e 4 \u4e2a\u6570\u5b57\u7684\u4e58\u79ef\u662f 0 * 2 * 5 * 4 = 0\\nproductOfNumbers.add(8);        // [3,0,2,5,4,8]\\nproductOfNumbers.getProduct(2); // \u8fd4\u56de 32 \u3002\u6700\u540e 2 \u4e2a\u6570\u5b57\u7684\u4e58\u79ef\u662f 4 * 8 = 32 \\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>add</code> \u548c <code>getProduct</code>&nbsp;\u4e24\u79cd\u64cd\u4f5c\u52a0\u8d77\u6765\u603b\u5171\u4e0d\u4f1a\u8d85\u8fc7&nbsp;<code>40000</code>&nbsp;\u6b21\u3002</li>\\n\\t<li><code>0 &lt;= num&nbsp;&lt;=&nbsp;100</code></li>\\n\\t<li><code>1 &lt;= k &lt;= 40000</code></li>\\n</ul>\\n","title":"1352. \u6700\u540e K \u4e2a\u6570\u7684\u4e58\u79ef","relatedTags":["\u8bbe\u8ba1","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1352"}')}}]);